import{_ as i,o as l,c as e,a3 as o}from"./chunks/framework.gsMzR_Kb.js";const p=JSON.parse('{"title":"核心概念","description":"易经学习中最先需要稳定下来的概念入口。","frontmatter":{"title":"核心概念","description":"易经学习中最先需要稳定下来的概念入口。"},"headers":[],"relativePath":"yijing/basics/core-concepts.md","filePath":"yijing/basics/core-concepts.md","lastUpdated":1777132262000}'),r={name:"yijing/basics/core-concepts.md"};function t(n,a,s,c,h,d){return l(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h1><p>《易经》最容易让初学者迷失的地方，不是句子本身，而是这些反复出现的关键词。</p><p>它们看起来简短，却几乎决定了你后面能不能把卦、爻、传文读成一个系统。</p><h2 id="为什么要先稳住概念" tabindex="-1">为什么要先稳住概念 <a class="header-anchor" href="#为什么要先稳住概念" aria-label="Permalink to &quot;为什么要先稳住概念&quot;">​</a></h2><p>若没有概念层，读《易》很容易出现两种情况：</p><ul><li>每遇到一个词都要重新解释一次</li><li>同一个词在不同老师、不同材料里越看越乱</li></ul><p>所以这里先不追求“定于一尊”，而是先建立一套够用、可迭代、能互相链接的概念入口。</p><h2 id="当前优先建立这些概念卡" tabindex="-1">当前优先建立这些概念卡 <a class="header-anchor" href="#当前优先建立这些概念卡" aria-label="Permalink to &quot;当前优先建立这些概念卡&quot;">​</a></h2><ul><li>阴 / 阳</li><li>刚 / 柔</li><li>中 / 正</li><li>位</li><li>应</li><li>时</li><li>变易</li><li>象 / 理 / 用</li></ul><p>每个概念建议后续单独成页，而不是全部堆在一篇大文里。</p><p>原因很简单：</p><ul><li>更利于检索</li><li>更利于内链</li><li>更利于后续做知识库切片</li></ul><h2 id="这八个概念可以先分三组理解" tabindex="-1">这八个概念可以先分三组理解 <a class="header-anchor" href="#这八个概念可以先分三组理解" aria-label="Permalink to &quot;这八个概念可以先分三组理解&quot;">​</a></h2><h3 id="第一组-结构基础" tabindex="-1">第一组：结构基础 <a class="header-anchor" href="#第一组-结构基础" aria-label="Permalink to &quot;第一组：结构基础&quot;">​</a></h3><ul><li>阴阳：最基本的分化关系</li><li>刚柔：气质、力量、趋向的区分</li><li>位：某一爻所处的位置是否得当</li><li>应：上下卦之间的对应关系</li></ul><h3 id="第二组-判断尺度" tabindex="-1">第二组：判断尺度 <a class="header-anchor" href="#第二组-判断尺度" aria-label="Permalink to &quot;第二组：判断尺度&quot;">​</a></h3><ul><li>中正：是否居中、是否得正</li><li>时：当下处境与时势是否相合</li><li>变易：事物如何在运动中转化</li></ul><h3 id="第三组-理解方法" tabindex="-1">第三组：理解方法 <a class="header-anchor" href="#第三组-理解方法" aria-label="Permalink to &quot;第三组：理解方法&quot;">​</a></h3><ul><li>象理用：怎么从象入手，再通到理，最后落到用</li></ul><h2 id="进入这些概念时的基本提醒" tabindex="-1">进入这些概念时的基本提醒 <a class="header-anchor" href="#进入这些概念时的基本提醒" aria-label="Permalink to &quot;进入这些概念时的基本提醒&quot;">​</a></h2><ul><li>不要急着把它们都读成抽象哲学</li><li>也不要把它们都读成固定术语表</li><li>更好的读法，是一边看概念页，一边回到卦爻语境里验证</li></ul><h2 id="当前骨架" tabindex="-1">当前骨架 <a class="header-anchor" href="#当前骨架" aria-label="Permalink to &quot;当前骨架&quot;">​</a></h2><ul><li><a href="/Dao/yijing/basics/concepts/yin-yang">阴阳</a></li><li><a href="/Dao/yijing/basics/concepts/gang-rou">刚柔</a></li><li><a href="/Dao/yijing/basics/concepts/zhong-zheng">中正</a></li><li><a href="/Dao/yijing/basics/concepts/wei">位</a></li><li><a href="/Dao/yijing/basics/concepts/ying">应</a></li><li><a href="/Dao/yijing/basics/concepts/shi">时</a></li><li><a href="/Dao/yijing/basics/concepts/bian-yi">变易</a></li><li><a href="/Dao/yijing/basics/concepts/xiang-li-yong">象理用</a></li></ul><h2 id="继续往下读时-可以配合这些页面" tabindex="-1">继续往下读时，可以配合这些页面 <a class="header-anchor" href="#继续往下读时-可以配合这些页面" aria-label="Permalink to &quot;继续往下读时，可以配合这些页面&quot;">​</a></h2><ul><li><a href="/Dao/yijing/basics/learning-method">学习方法</a></li><li><a href="/Dao/yijing/hexagrams/">六十四卦目录</a></li><li><a href="/Dao/topics/yin-yang">专题：阴阳</a></li><li><a href="/Dao/topics/bian-yi">专题：变易</a></li><li><a href="/Dao/topics/xiang-li-yong">专题：象理用</a></li></ul>',25)])])}const b=i(r,[["render",t]]);export{p as __pageData,b as default};
